import pytest from sqlalchemy import create_engine from sqlalchemy.orm import sessionmaker from testcontainers.postgres import PostgresContainer from app.models import Base
@pytest.fixture(scope="session") def engine(): with PostgresContainer("postgres:16-alpine") as pg: e = create_engine(pg.get_connection_url()) Base.metadata.create_all(e) yield e
@pytest.fixture def session(engine): conn = engine.connect() tx = conn.begin() Session = sessionmaker(bind=conn) db = Session() yield db db.close() tx.rollback() conn.close()

import uuid
import pytest
import respx
from fastapi.testclient import TestClient
from httpx import Response

from app.main import app, get_db


@pytest.fixture
def client(session):
    app.dependency_overrides[get_db] = lambda: session
    with TestClient(app) as c:
        yield c
    app.dependency_overrides.clear()


@pytest.fixture
def unique_email():
    return f"test-{uuid.uuid4()}@example.com"


@respx.mock
def test_register_calls_billing(client, unique_email):
    respx.post("https://billing.example.com/customers").mock(
        return_value=Response(201, json={"id": "cust_x"})
    )
    r = client.post("/api/users", json={"email": unique_email})
    assert r.status_code == 201
    assert respx.calls.call_count == 1
